script:
frappe.listview_settings['Buyback Price Master'] = {
    onload(listview) {
        if (listview._ch_info_added) return;
        listview._ch_info_added = true;

        listview.page.add_inner_button('Open Ready Reckoner', () => {
            frappe.set_route('ch-ready-reckoner');
        });

        listview.page.set_indicator('Read Only', 'blue');
    }
};

frappe.ui.form.on('Buyback Request', {
    refresh(frm) {
        apply_mode(frm);
    },
    mode(frm) {
        apply_mode(frm);
    }
});

function apply_mode(frm) {

    let is_buyback = frm.doc.mode === "BuyBack";

    frm.toggle_display("buyback_section", is_buyback);
    frm.toggle_display("diagnosis_section", !is_buyback);

    frm.dashboard.clear_headline();
    frm.dashboard.set_headline(
        is_buyback ? "BuyBack Mode Active" : "Diagnosis Mode Active"
    );
}

frappe.ui.form.on('Buyback Request', {
    refresh(frm) {
        if (frm.is_new()) calc_price(frm);
    },

    item_id: calc_price,
    usage_key: calc_price,
    grade: calc_price
});

function calc_price(frm) {

    // stop if fields missing
    if (!frm.doc.item_id || !frm.doc.usage_key || !frm.doc.grade) {
        frm.set_value('buyback_price', 0);
        frm.set_value('final_buyback_amount', 0);
        frm.set_value('cash_notes', 0);
        return;
    }

    // build dynamic field name
    let key = `${frm.doc.grade}_grade_${frm.doc.usage_key}`;
    console.log("PRICE KEY →", key);


    frappe.db.get_doc('Buyback Price Master', frm.doc.item_id)
        .then(doc => {

            let price = doc[key] || 0;
            console.log("FETCHED PRICE →", price);

            frm.set_value('buyback_price', price);
            frm.set_value('final_buyback_amount', price);
            frm.set_value('cash_notes', price);

        })
        .catch(err => {
            console.error("Price fetch error:", err);
            frm.set_value('buyback_price', 0);
            frm.set_value('final_buyback_amount', 0);
            frm.set_value('cash_notes', 0);
        });
}

frappe.ui.form.on('Buyback Request', {
    refresh: function(frm) {

        if (frm.is_new()) {
            frm.set_value('buyback_request_staff', frappe.session.user);
        }
    }
});

frappe.ui.form.on('Buyback Request', {

    refresh(frm) {
        show_preview(frm);
    },

    customer_image(frm) {
        show_preview(frm);
    }
});

function show_preview(frm) {

    if (!frm.doc.customer_image) {
        frm.set_value('customer_image_preview', '');
        return;
    }

    let url = window.location.origin + frm.doc.customer_image;

    frm.set_value('customer_image_preview', url);
}

frappe.ui.form.on('Buyback Request', {
    payment_mode: function(frm) {
        payment_ui(frm);
    },
    refresh: function(frm) {
        payment_ui(frm);
    }
});

function payment_ui(frm) {

    // hide everything first
    frm.toggle_display([
        'cash_notes',
        'account_holder_name',
        'branch',
        'bank_name',
        'ifsc_code',
        'upi_id',
         'account_no',
        'transaction_proof'
    ], false);

    // always show amount
    frm.toggle_display('final_buyback_amount', true);

    if (!frm.doc.payment_mode) return;

    frappe.db.get_doc('Payment Method Master', frm.doc.payment_mode)
        .then(doc => {

            frm.set_value('payment_mode_name', doc.payment_method);

            // CASH
            if (doc.payment_method === "cash") {
                frm.toggle_display('cash_notes', true);
            }

            // BANK
            else if (doc.payment_method === "bank transfer") {
                frm.toggle_display([
                    'account_holder_name',
                    'branch',
                    'bank_name',
                    'ifsc_code',
                     'account_no',
                     'transaction_proof'
                ], true);
            }

            // UPI
            else if (doc.payment_method === "upi") {
                frm.toggle_display([
                    'upi_id',
                    'transaction_proof'
                ], true);
            }

        });
}

frappe.ui.form.on('Buyback Request', {
    refresh: function(frm) {
        toggle_no_deal(frm);
    },

    deal_status: function(frm) {
        toggle_no_deal(frm);
    }
});

function toggle_no_deal(frm) {
    if (frm.doc.deal_status === "No Deal") {
        frm.set_df_property('no_deal_reason', 'hidden', 0);
        frm.set_df_property('no_deal_reason', 'reqd', 1);
    } else {
        frm.set_df_property('no_deal_reason', 'hidden', 1);
        frm.set_df_property('no_deal_reason', 'reqd', 0);
        frm.set_value('no_deal_reason', '');
    }
}

frappe.ui.form.on('Buyback Request', {
    refresh(frm) {
        bind_integer_fields(frm);
    }
});

function bind_integer_fields(frm) {


    const integer_fields = ['mobile_no', 'pincode', 'imei'];

    integer_fields.forEach(fieldname => {

        const field = frm.fields_dict[fieldname];
        if (!field || !field.$input) return;

        const input = field.$input;

        // remove previous bindings
        input.off('.numeric');


        input.on('keypress.numeric', function (e) {

            const allowedKeys = [
                "Backspace", "Delete", "Tab",
                "ArrowLeft", "ArrowRight",
                "Home", "End"
            ];

            if (e.ctrlKey || e.metaKey || allowedKeys.includes(e.key)) {
                return;
            }

            if (!/^[0-9]$/.test(e.key)) {
                e.preventDefault();
            }
        });

            input.on('paste.numeric', function (e) {
            const pasted = (e.originalEvent || e).clipboardData.getData('text');
            if (!/^\d+$/.test(pasted)) {
                e.preventDefault();
            }
        });


        input.on('input.numeric', function () {
            this.value = this.value.replace(/\D/g, '');
        });
    });
}

frappe.ui.form.on('Buyback Price Master', {
    refresh(frm) {
        render_price_grid(frm);
    }
});

function render_price_grid(frm) {
    if (frm.is_new()) return;

    const fmt = (v) => {
        v = flt(v);
        if (!v) return '<span style="color:#ccc">—</span>';
        return format_currency(v, frm.doc.currency || 'INR');
    };

    const periods = [
        { label: 'IW 0–3 Mo',  suffix: 'In Warranty',     grades: ['a_grade_iw_0_3','b_grade_iw_0_3','c_grade_iw_0_3',''] },
        { label: 'IW 0–6 Mo',  suffix: 'In Warranty',     grades: ['a_grade_iw_0_6','b_grade_iw_0_6','c_grade_iw_0_6','d_grade_iw_0_6'] },
        { label: 'IW 6–11 Mo', suffix: 'In Warranty',     grades: ['a_grade_iw_6_11','b_grade_iw_6_11','c_grade_iw_6_11','d_grade_iw_6_11'] },
        { label: 'OOW 11+ Mo',     suffix: 'Out of Warranty', grades: ['a_grade_oow_11','b_grade_oow_11','c_grade_oow_11','d_grade_oow_11'] }
    ];

    let rows = '';
    for (let i = 0; i < periods.length; i++) {
        let p = periods[i];
        let bg = i % 2 === 0 ? '#fff' : '#f8fafb';
        rows += `<tr style="background:${bg}">`;
        rows += `<td style="padding:10px 14px;font-weight:500;color:#333;border-bottom:1px solid #eee">${p.label}</td>`;
        for (let g of p.grades) {
            let val = g ? fmt(frm.doc[g]) : '';
            rows += `<td style="text-align:right;padding:10px 14px;border-bottom:1px solid #eee;color:#36414C">${val}</td>`;
        }
        rows += '</tr>';
    }

    const html = `
    <div style="display:flex;gap:16px;margin-bottom:16px">
        <div style="flex:1;background:linear-gradient(135deg,#667eea 0%,#764ba2 100%);border-radius:10px;padding:18px 20px;color:#fff">
            <div style="font-size:11px;text-transform:uppercase;letter-spacing:0.5px;opacity:0.85;margin-bottom:4px">Market Price</div>
            <div style="font-size:22px;font-weight:700">${fmt(frm.doc.current_market_price)}</div>
        </div>
        <div style="flex:1;background:linear-gradient(135deg,#11998e 0%,#38ef7d 100%);border-radius:10px;padding:18px 20px;color:#fff">
            <div style="font-size:11px;text-transform:uppercase;letter-spacing:0.5px;opacity:0.85;margin-bottom:4px">Vendor Price</div>
            <div style="font-size:22px;font-weight:700">${fmt(frm.doc.vendor_price)}</div>
        </div>
    </div>
    <div style="border:1px solid #e2e6ea;border-radius:8px;overflow:hidden">
        <table style="width:100%;border-collapse:collapse;font-size:13px">
            <thead><tr style="background:#f1f3f5">
                <th style="padding:10px 14px;text-align:left;font-weight:600;color:#555;border-bottom:2px solid #dee2e6">Warranty Period</th>
                <th style="padding:10px 14px;text-align:right;font-weight:600;color:#555;border-bottom:2px solid #dee2e6">Grade A</th>
                <th style="padding:10px 14px;text-align:right;font-weight:600;color:#555;border-bottom:2px solid #dee2e6">Grade B</th>
                <th style="padding:10px 14px;text-align:right;font-weight:600;color:#555;border-bottom:2px solid #dee2e6">Grade C</th>
                <th style="padding:10px 14px;text-align:right;font-weight:600;color:#555;border-bottom:2px solid #dee2e6">Grade D</th>
            </tr></thead>
            <tbody>${rows}</tbody>
        </table>
    </div>`;

    frm.fields_dict.price_grid_html.$wrapper.html(html);
}
